const inp=$input.first().json||{};
function fromStr(s){s=String(s).trim();if(s.startsWith('{')){try{return JSON.parse(s);}catch(e){}}return {indicator:s};}
let raw=(inp.query!==undefined)?inp.query:inp; let a={};
if(typeof raw==='string'){a=fromStr(raw);}
else if(raw&&typeof raw==='object'){
  if(raw.indicator!==undefined||raw.ip!==undefined||raw.hash!==undefined||raw.domain!==undefined||raw.type!==undefined){a=raw;}
  else{const f=Object.values(raw)[0]; a=(typeof f==='string')?fromStr(f):(f&&typeof f==='object'?f:raw);}
}
let ind=String(a.indicator||a.ip||a.hash||a.domain||a.value||'').trim();
let typ=String(a.type||'').toLowerCase().trim();
// auto-detection si type absent
if(!typ){
  if(/^\d{1,3}(\.\d{1,3}){3}$/.test(ind))typ='ip';
  else if(/^[a-fA-F0-9]{64}$|^[a-fA-F0-9]{40}$|^[a-fA-F0-9]{32}$/.test(ind))typ='hash';
  else typ='domain';
}
const epmap={ip:'ip_addresses',hash:'files',domain:'domains',file:'files',url:'urls'};
const endpoint=epmap[typ]||'domains';
return [{json:{endpoint, indicator:ind, type:typ}}];

const r=$input.first().json||{};
const code=(r.statusCode!==undefined)?r.statusCode:200;
const body=(r.body!==undefined)?r.body:r;
const ind=$('Parse').first().json.indicator;
const typ=$('Parse').first().json.type;
if(code===429)return [{json:{indicator:ind,error:'Quota VirusTotal depasse (HTTP 429). Reessaie plus tard.'}}];
if(code===404)return [{json:{indicator:ind,found:false,msg:'Indicateur inconnu de VirusTotal (404).'}}];
if(code>=400)return [{json:{indicator:ind,error:'VirusTotal HTTP '+code}}];
const at=(body&&body.data&&body.data.attributes)||{};
const st=at.last_analysis_stats||{};
const total=(st.malicious||0)+(st.suspicious||0)+(st.harmless||0)+(st.undetected||0)+(st.timeout||0);
return [{json:{indicator:ind, type:typ, malicious:st.malicious||0, suspicious:st.suspicious||0,
  harmless:st.harmless||0, undetected:st.undetected||0, total_engines:total,
  reputation:at.reputation, as_owner:at.as_owner, country:at.country,
  verdict:((st.malicious||0)>0?'MALVEILLANT':((st.suspicious||0)>0?'SUSPECT':'propre'))}}];
